'use client'
import { cn } from '@cascivo/core'
import type { HTMLAttributes } from 'react'
import styles from './text.module.css'

export interface TextProps extends HTMLAttributes<HTMLElement> {
  as?: 'p' | 'span' | 'div'
  size?: 'sm' | 'md' | 'lg'
  weight?: 'normal' | 'medium' | 'semibold'
  muted?: boolean
}

export function Text({
  as: Tag = 'p',
  size = 'md',
  weight = 'normal',
  muted = false,
  className,
  children,
  ...props
}: TextProps) {
  return (
    <Tag
      data-size={size}
      data-weight={weight}
      data-muted={muted ? '' : undefined}
      className={cn(styles['text'], className as string | undefined)}
      {...(props as Record<string, unknown>)}
    >
      {children}
    </Tag>
  )
}

@layer cascivo.component {
  .text {
    margin: 0;
    font-family: var(--cascivo-font-sans);
    line-height: var(--cascivo-leading-normal);
    color: var(--cascivo-color-text);

    &[data-size='sm'] {
      font-size: var(--cascivo-text-sm);
    }

    &[data-size='md'] {
      font-size: var(--cascivo-text-base);
    }

    &[data-size='lg'] {
      font-size: var(--cascivo-text-lg);
    }

    &[data-weight='normal'] {
      font-weight: var(--cascivo-font-normal);
    }

    &[data-weight='medium'] {
      font-weight: var(--cascivo-font-medium);
    }

    &[data-weight='semibold'] {
      font-weight: var(--cascivo-font-semibold);
    }

    &[data-muted] {
      color: var(--cascivo-color-text-subtle);
    }
  }
}
